 * Genera el documento Word utilizando una plantilla y Docxtemplater.
 * @param {object} documentData - Datos de las secciones.
 * @param {Array<object>} procedureData - Datos de la tabla de procedimiento.
 * @returns {Promise<boolean>}
 */
export async function generateWordDocument(documentData, procedureData) {
  try {
    // --- 1. Preparación de Datos ---
    const today = documentData.headerConfig?.fecha ? new Date(documentData.headerConfig.fecha) : new Date();
    const formattedDate = `${today.getDate().toString().padStart(2, '0')}-${(today.getMonth() + 1).toString().padStart(2, '0')}-${today.getFullYear()}`;

    // Mapeo de datos para Docxtemplater (un solo objeto)
    const payload = {
      // Header: Se usan los nombres de las variables de Vue
      manualName: documentData.headerConfig?.manualName || 'Manual de Políticas y Procedimientos',
      policyName: documentData.headerConfig?.policyName || 'PROCEDIMIENTO',
      codigo: documentData.headerConfig?.codigo || 'XX-P-XXX-#',
      area: documentData.headerConfig?.area || 'Área responsable',
      unidad: documentData.headerConfig?.unidad || 'Unidad específica',
      revision: documentData.headerConfig?.revision || '(1)',
      fecha: formattedDate,
      // Secciones: Se usan los nombres de las variables de Vue
      objetivo: documentData.objetivo || 'Contenido pendiente de completar.',
      alcance: documentData.alcance || 'Contenido pendiente de completar.',
      responsabilidades: documentData.responsabilidades || 'Contenido pendiente de completar.',
      normativa: documentData.normativa || 'Contenido pendiente de completar.',
      anexos: documentData.anexos || 'Contenido pendiente de completar.',
      terminos: documentData.terminos || 'Contenido pendiente de completar.',
      // Procedimiento (Array para iteración en tabla)
      procedimiento: procedureData.map(row => {
        let number = String(row.number || '').trim();
        // Ajuste del número de procedimiento para que inicie con 5.
        if (number && !number.startsWith('5.')) {
          if (!number.includes('.') && !isNaN(number)) {
            number = `5.${number}`;
          } else if (number.startsWith('5')) {
            // Si solo pone '5'
            number = '5.';
          } else {
            // Si tiene subniveles
            const segments = number.split('.');
            if (segments.every(seg => /^\d+$/.test(seg.trim()))) {
              number = `5.${number}`;
            }
          }
        }

        // Docxtemplater automáticamente realiza el escape XML necesario aquí.
        return {
          number: number,
          who: String(row.who || '').trim(),
          activity: String(row.activity || '').trim(),
          // Si necesita el nivel para dar formato en la plantilla:
          level: row.level
        };
      })
    };

    // --- 2. Carga de la Plantilla ---
    // DEBE reemplazar 'ruta/a/su/Template.docx' con la ubicación real
    // donde ha guardado la plantilla que creó en Word.
    const templateContent = await loadTemplate('/assets/Template.docx'); // Ejemplo de ruta

    // --- 3. Inicialización de Docxtemplater ---
    const zip = new PizZip(templateContent);
    const doc = new Docxtemplater(zip, {
      paragraphLoop: true,
      // Habilita la repetición de filas en tablas
      linebreaks: true // Conserva saltos de línea (\n) dentro de las variables
    });

    // --- 4. Renderizado ---
    doc.setData(payload);
    doc.render();

    // --- 5. Descarga ---
    const out = doc.getZip().generate({
      type: 'blob',
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      compression: 'DEFLATE'
    });
    const fileName = `${payload.policyName.replace(/[^a-z0-9]/gi, '_')}.docx`;

    // Lógica de descarga
    if (window.navigator && window.navigator.msSaveOrOpenBlob) {
      window.navigator.msSaveOrOpenBlob(out, fileName);
    } else {
      const url = URL.createObjectURL(out);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
      }, 100);
    }
    return true;
  } catch (error) {
    console.error("Error al generar el documento con Docxtemplater:", error);
    throw new Error(`Error en la generación del documento: ${error.message}`);
  }
}

